>\r\n                                                <th>#</th>\r\n                                                <th>Cliente</th>\r\n                                                <th class=\"text-end\">\r\n                                                    Trans.\r\n                                                    <el-tooltip\r\n                                                        class=\"item\"\r\n                                                        effect=\"dark\"\r\n                                                        content=\"Transacciones (Cantidad de ventas realizadas)\"\r\n                                                        placement=\"top-start\"\r\n                                                    >\r\n                                                        <i\r\n                                                            class=\"fa fa-info-circle\"\r\n                                                        ></i>\r\n                                                    </el-tooltip>\r\n                                                </th>\r\n                                                <th class=\"text-end\">Total</th>\r\n                                            </tr>\r\n                                        </thead>\r\n                                        <tbody>\r\n                                            <template\r\n                                                v-for=\"(row,\r\n                                                index) in top_customers\"\r\n                                            >\r\n                                                <tr :key=\"index\">\r\n                                                    <td>{{ index + 1 }}</td>\r\n                                                    <td>\r\n                                                        {{ row.name }}\r\n                                                        <br />\r\n                                                        <small\r\n     