vue\";\r\nimport queryString from \"query-string\";\r\n\r\nexport default {\r\n    props: [\"typeUser\", \"soapCompany\"],\r\n    components: { DashboardStock },\r\n    data() {\r\n        return {\r\n            loading_search: false,\r\n            records_base: [],\r\n            selected_customer: null,\r\n            customers: [],\r\n            resource: \"dashboard\",\r\n            establishments: [],\r\n            balance: {\r\n                totals: {},\r\n                graph: {}\r\n            },\r\n            count_documents:{\r\n                totals: {},\r\n                graph: {}\r\n            },\r\n            \r\n            document: {\r\n                totals: {},\r\n                graph: {}\r\n            },\r\n            sale_note: {\r\n                totals: {},\r\n                graph: {}\r\n            },\r\n            general: {\r\n                totals: {},\r\n                graph: {}\r\n            },\r\n            purchase: {\r\n                totals: {},\r\n                graph: {}\r\n            },\r\n            utilities: {\r\n                totals: {},\r\n                graph: {}\r\n            },\r\n            disc: [],\r\n            form: {},\r\n            pickerOptionsDates: {\r\n                disabledDate: time => {\r\n                    time = moment(time).format(\"YYYY-MM-DD\");\r\n                    return this.form.date_start > time;\r\n                }\r\n            },\r\n            pickerOptionsMonths: {\r\n                disabledDate: time => {\r\n                    time = moment(time).format(\"YYYY-MM\");\r\n                    return this.form.month_start > time;\r\n                }\r\n            },\r\n            records: [],\r\n            items_by_sales: [],\r\n            top_customers: [],\r\n            recordId: null,\r\n            showDialogDocumentPayments: false,\r\n            showDialogSaleNotePayments: false,\r\n            filter_item: false,\r\n            all_items: [],\r\n            items: [],\r\n            total: 0,\r\n            document_total_global: 0.0,\r\n            total_cpe: 0,\r\n            sale_note_total_global: 0.0\r\n        };\r\n    },\r\n    async created() {\r\n        this.initForm();\r\n        await this.$http.get(`/${this.resource}/filter`).then(response => {\r\n            this.establishments = response.data.establishments;\r\n            this.form.establishment_id =\r\n                this.establishments.length > 0\r\n                    ? this.establishments[0].id\r\n                    : null;\r\n        });\r\n        await this.loadAll();\r\n        await this.filterItems();\r\n        await this.onFetchData();\r\n        console.log(this.utilities);\r\n        // this.$eventHub.$on(\"reloadDataUnpaid\", () => {\r\n        //   this.loadAll();\r\n        // });\r\n    },\r\n\r\n    methods: {\r\n        changeFilterItem() {\r\n            this.form.item_id = null;\r\n            this.loadDataUtilities();\r\n        },\r\n        searchRemoteItems(input) {\r\n            if (input.length > 1) {\r\n                this.loading_search = true;\r\n                let parameters = `input=${input}`;\r\n\r\n                this.$http\r\n                    .get(`/reports/data-table/items/?${parameters}`)\r\n                    .then(response => {\r\n                        this.items = response.data.items;\r\n                        this.loading_search = false;\r\n\r\n                        if (this.items.length == 0) {\r\n                            this.filterItems();\r\n                        }\r\n                    });\r\n            } else {\r\n                this.filterItems();\r\n            }\r\n        },\r\n        filterItems() {\r\n            this.items = this.all_items;\r\n        },\r\n        calculateTotalCurrency(currency_type_id, exchange_rate_sale, total) {\r\n            if (currency_type_id == \"USD\") {\r\n                return parseFloat(total) * exchange_rate_sale;\r\n      